<script>const pf=document.getElementById('preview-frame'),url=<?=json_encode($preview,JSON_UNESCAPED_SLASHES)?>;function refresh(){pf.src=url+'&r='+Date.now()}document.getElementById('preview-refresh').onclick=refresh;document.querySelectorAll('[data-size]').forEach(b=>b.onclick=()=>{pf.className='preview-frame '+(b.dataset.size==='desktop'?'':b.dataset.size)});let hash='';let timer;setInterval(async()=>{try{const r=await fetch('estado.php',{credentials:'same-origin',cache:'no-store'});if(!r.ok)return;const d=await r.json();if(hash&&hash!==d.hash){clearTimeout(timer);timer=setTimeout(refresh,900)}hash=d.hash}catch(e){}},2000);</script><?php cmsPie();
